interface N8nExecutionData { node: { name: string; type: string }; json: any; }

function detectTriggerLoop(data: N8nExecutionData[]): boolean {
  const aiNodes = data.filter(n => n.node.type.includes('ai') || n.node.name.includes('Agent'));
  const currentWorkflowId = process.env.WORKFLOW_ID || '';

  return aiNodes.some(node => {
    const output = node.json.output || node.json;
    const webhookPatterns = [
      `webhook/${currentWorkflowId}`,
      new RegExp(`n8n\.workflow\.webhook.*${currentWorkflowId}`, 'i'),
      /https?:\/\/[^\s]+n8n\.[^\s]+\/webhook\/[^\s]+/i
    ];

    return webhookPatterns.some(pattern => 
      typeof output === 'string' ? pattern.test(output) : 
      JSON.stringify(output).match(pattern)
    );
  });
}

function detectToolRecursion(items: any[]): { isLoop: boolean; depth: number } {
  let toolDepth = 0;
  let parentIds: string[] = [];

  for (const item of items) {
    const executionData = item.json.$execution || {};
    if (executionData.parentExecutionId) {
      toolDepth++;
      parentIds.push(executionData.parentExecutionId);

      // Detect self-reference
      if (parentIds.includes(executionData.id)) {
        return { isLoop: true, depth: toolDepth };
      }
    }
  }

  return { isLoop: toolDepth > 5, depth: toolDepth };
}

function detectMemoryLoops(memoryItems: any[]): boolean {
  const toolCallRegex = /tool_call|function_call|action:\s*\w+/gi;
  const messages = memoryItems.flatMap(item => item.json.messages || []);

  const toolSequences: string[] = [];
  let currentSeq = '';

  for (const msg of messages.slice(-10)) { // Last 10 messages
    const toolMatches = (msg.content || '').match(toolCallRegex);
    if (toolMatches) {
      currentSeq += toolMatches.join(' ');
      if (currentSeq.length > 100) {
        toolSequences.push(currentSeq);
        currentSeq = '';
      }
    }
  }

  // Check for repeating sequences
  const seqSet = new Set(toolSequences);
  return toolSequences.length > 2 && seqSet.size < toolSequences.length / 2;
}

