const items = $input.all();
const fixedItems = items.map(item => {
  const output = item.json.output || item.json;

  // Block webhook triggers
  if (typeof output === 'string' && /webhook\//i.test(output)) {
    return {
      json: {
        ...item.json,
        output: 'LOOP_DETECTED: Webhook recursion blocked',
        safe_to_proceed: false,
        loop_type: 'trigger_recursion'
      }
    };
  }

  // Limit tool call depth
  const execData = $execution;
  if (execData.parentExecutions?.length > 3) {
    return {
      json: {
        ...item.json,
        output: 'LOOP_DETECTED: Max recursion depth exceeded',
        safe_to_proceed: false,
        loop_type: 'depth_exceeded'
      }
    };
  }

  return { json: { ...item.json, safe_to_proceed: true } };
});

return fixedItems.filter(item => item.json.safe_to_proceed);

// Code node with n8n workflow static data
async function trackLoopState() {
  const workflowStaticData = await $workflow.staticData();
  const executionId = $execution.id;
  const toolCalls = workflowStaticData.toolCalls || [];

  toolCalls.push({
    executionId,
    timestamp: Date.now(),
    nodeName: $node.name
  });

  // Prune old calls
  workflowStaticData.toolCalls = toolCalls.filter(
    call => Date.now() - call.timestamp < 60000 // 1 min window
  );

  // Detect loops
  const recentCalls = workflowStaticData.toolCalls.slice(-5);
  const isLoop = recentCalls.length > 3 && 
    recentCalls.some((call, i) => 
      i > 0 && call.nodeName === recentCalls[0].nodeName
    );

  await $workflow.staticData('toolCalls', workflowStaticData.toolCalls);

  if (isLoop) {
    throw new Error('LOOP_DETECTED: Terminating recursive execution');
  }

  return $input.all();
}

return await trackLoopState();

const items = $input.all();
const safeItems = items.map(item => {
  const toolCall = item.json.tool_calls?.[0] || item.json;
  if (!toolCall) return item;

  const params = toolCall.function?.arguments || toolCall.parameters || {};

  // Block self-referential URLs
  const urls = Object.values(params).filter(v => typeof v === 'string');
  const selfWebhook = urls.some(url => 
    url.includes('n8n') && (url.includes('webhook') || url.includes($workflow.id))
  );

  // Block credential patterns
  const creds = urls.some(url => /api_key|token|secret/i.test(url));

  if (selfWebhook || creds) {
    return {
      json: {
        ...item.json,
        blocked: true,
        reason: selfWebhook ? 'self_webhook' : 'credential_exposure',
        safe_params: { ...params, dangerous_urls: urls }
      }
    };
  }

  return item;
});

return safeItems.filter(item => !item.json.blocked);

