import { Vex } from '@vex_dev/sdk';

const vex = new Vex({
  projectId: process.env.VEX_PROJECT_ID!,
  webhookToken: process.env.VEX_WEBHOOK_TOKEN!
});

// n8n Code node - Vex integration after AI Agent
export default defineN8nCodeNode({
  async run({ items, $execution }) {
    // Send execution trace to Vex
    const trace = {
      workflowId: $execution.workflowData.id,
      nodeName: $node.name,
      inputData: items.map(i => i.json),
      executionId: $execution.id,
      parentId: $execution.parentExecution?.id
    };

    const { verdict, remediation } = await vex.check({
      type: 'n8n_ai_loop',
      trace,
      patterns: ['webhook_recursion', 'tool_depth_exceeded', 'memory_loop'],
      maxDepth: 5
    });

    if (verdict === 'LOOP_DETECTED') {
      // Apply Vex remediation
      return [{
        json: {
          ...remediation,
          vex_verdict: verdict,
          loop_type: remediation.loop_type,
          fixed: true
        }
      }];
    }

    // Forward safe execution
    return items.map(item => ({ json: { ...item.json, vex_clear: true } }));
  }
});
